<?php require '../includes/functions.php'; $slug=basename(rtrim($_SERVER['REQUEST_URI'],'/')); $label=ucwords(str_replace('-',' ',$slug)); $pageTitle=$label.' | Local Legends Orlando'; require '../includes/header.php'; $articles=public_articles(24, $slug); ?><section class="page-intro"><p class="eyebrow">Category</p><h1><?=e($label)?></h1><p>Stories of the people and places that make this corner of Orlando special.</p></section><section class="section"><div class="story-grid story-grid-three"><?php foreach($articles as $article): ?><article class="story-card"><a class="card-image" href="<?=article_public_url($article) ?>"><img src="<?=media_url($article['image'] ?? null)?>" alt="" loading="lazy"></a><div class="card-body"><h2><a href="<?=article_public_url($article) ?>"><?=e($article['title'])?></a></h2><p><?=e($article['excerpt'])?></p></div></article><?php endforeach;?></div></section><?php require '../includes/footer.php'; ?>
